#include<bits/stdc++.h>
using namespace std;
long long b[100010];
long long mod;
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long sum;
        long long add_tag,mul_tag;
        node():add_tag(0),mul_tag(1){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum)%mod;
    }
    void pushdown(long long x)
    {
        long long l=a[x].l,r=a[x].r,ls=a[x].lson,rs=a[x].rson;
        long long mid=(l+r)>>1,mtg=a[x].mul_tag,atg=a[x].add_tag;
        a[ls].sum=(a[ls].sum*mtg%mod+(mid-l+1)*atg%mod)%mod;
        a[rs].sum=(a[rs].sum*mtg%mod+(r-mid)*atg%mod)%mod;
        a[ls].mul_tag=a[ls].mul_tag*mtg%mod;
        a[rs].mul_tag=a[rs].mul_tag*mtg%mod;
        a[ls].add_tag=(a[ls].add_tag*mtg+atg)%mod;
        a[rs].add_tag=(a[rs].add_tag*mtg+atg)%mod;
        a[x].add_tag=0;
        a[x].mul_tag=1;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        a[x].mul_tag=1;
        a[x].add_tag=0;
        if(l==r)
        {
            a[x].sum=b[l]%mod;
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].add_tag+=v;
            a[x].sum+=(a[x].r-a[x].l+1)*v;
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,v);
        add(a[x].rson,l,r,v);
        pushup(x);
    }
    void mul(long long x,long long l,long long r,long long v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].mul_tag=a[x].mul_tag*v%mod;
            a[x].add_tag=a[x].add_tag*v%mod;
            a[x].sum=a[x].sum*v%mod;
            return;
        }
        pushdown(x);
        mul(a[x].lson,l,r,v);
        mul(a[x].rson,l,r,v);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r))%mod;
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld%lld",&n,&m,&mod);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        long long op,x,y,k;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            scanf("%lld",&k);
            t.mul(1,x,y,k);
        }
        else if(op==2)
        {
            scanf("%lld",&k);
            t.add(1,x,y,k);
        }
        else
        {
            printf("%lld\n",t.getsum(1,x,y));
        }
    }
    return 0;
}
